INSERT INTO `activity_logs` VALUES (1,12,'Ibu Arimbi','superadmin','update','App\\Models\\Article',1,'Memperbarui data Article','{\"content\":\"<p>Pelayanan rutin Posyandu terus ditingkatkan untuk memastikan tumbuh kembang anak yang optimal dan kesehatan ibu yang terjaga. Melalui berbagai program seperti imunisasi, pemberian vitamin, dan edukasi gizi, Posyandu menjadi garda terdepan dalam menciptakan generasi yang sehat dan kuat.<\\/p><p>Pemeriksaan rutin setiap bulan sangat penting untuk memantau perkembangan berat badan dan tinggi badan anak, serta memberikan konseling gizi kepada para ibu.<\\/p>\",\"thumbnail\":null,\"slug\":\"menjaga-kesehatan-ibu-dan-anak\",\"updated_at\":\"2026-06-30T04:30:03.000000Z\"}','{\"content\":\"[{\\\"type\\\":\\\"paragraph\\\",\\\"content\\\":\\\"<p>Pelayanan rutin Posyandu terus ditingkatkan untuk memastikan tumbuh kembang anak yang optimal dan kesehatan ibu yang terjaga. Melalui berbagai program seperti imunisasi, pemberian vitamin, dan edukasi gizi, Posyandu menjadi garda terdepan dalam menciptakan generasi yang sehat dan kuat.<\\/p><p>Pemeriksaan rutin setiap bulan sangat penting untuk memantau perkembangan berat badan dan tinggi badan anak, serta memberikan konseling gizi kepada para ibu.<\\/p>\\\"}]\",\"thumbnail\":\"articles\\/MGrXd6GKefS12YCBLkszq5nXAGC9Orb2NKT5r3Pg.png\",\"slug\":\"menjaga-kesehatan-ibu-dan-anak-peran-posyandu-dalam-masyarakat\",\"updated_at\":\"2026-06-30 11:40:25\"}','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/149.0.0.0 Safari/537.36','2026-06-30 04:40:25',NULL),(2,12,'Ibu Arimbi','superadmin','update','App\\Models\\Article',2,'Memperbarui data Article','{\"content\":\"<p>Panduan gizi penting selama masa kehamilan agar ibu dan janin tetap sehat dan bertenaga sepanjang hari. MPASI yang sehat harus mengandung nutrisi makro dan mikro yang seimbang, mulai dari karbohidrat, protein hewani, hingga lemak sehat.<\\/p>\",\"thumbnail\":null,\"slug\":\"menu-sehat-mpasi-terbaik\",\"updated_at\":\"2026-06-30T04:30:03.000000Z\"}','{\"content\":\"[{\\\"type\\\":\\\"paragraph\\\",\\\"content\\\":\\\"<p>Panduan gizi penting selama masa kehamilan agar ibu dan janin tetap sehat dan bertenaga sepanjang hari. MPASI yang sehat harus mengandung nutrisi makro dan mikro yang seimbang, mulai dari karbohidrat, protein hewani, hingga lemak sehat.<\\/p>\\\"}]\",\"thumbnail\":\"articles\\/AQIb6xWiFzqb5LbtmmNjwZASIMYRWO5FknyrpJcU.png\",\"slug\":\"menu-sehat-pendamping-asi-mpasi-terbaik\",\"updated_at\":\"2026-06-30 11:43:54\"}','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/149.0.0.0 Safari/537.36','2026-06-30 04:43:54',NULL),(3,12,'Ibu Arimbi','superadmin','update','App\\Models\\Article',5,'Memperbarui data Article','{\"content\":\"<p>Ini adalah artikel edukasi kesehatan untuk memberikan wawasan lebih mendalam tentang pola hidup sehat di lingkungan keluarga.<\\/p>\",\"thumbnail\":null,\"slug\":\"tips-kesehatan-keluarga-2\",\"updated_at\":\"2026-06-30T04:30:03.000000Z\"}','{\"content\":\"[{\\\"type\\\":\\\"paragraph\\\",\\\"content\\\":\\\"<p>Ini adalah artikel edukasi kesehatan untuk memberikan wawasan lebih mendalam tentang pola hidup sehat di lingkungan keluarga.<\\/p>\\\"}]\",\"thumbnail\":\"articles\\/edsdysqDdeORd0VkxrRilHxUForOygDdPymScBvE.png\",\"slug\":\"tips-kesehatan-keluarga-bagian-2\",\"updated_at\":\"2026-06-30 11:47:57\"}','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/149.0.0.0 Safari/537.36','2026-06-30 04:47:57',NULL),(4,12,'Ibu Arimbi','superadmin','update','App\\Models\\Article',4,'Memperbarui data Article','{\"content\":\"<p>Ini adalah artikel edukasi kesehatan untuk memberikan wawasan lebih mendalam tentang pola hidup sehat di lingkungan keluarga.<\\/p>\",\"thumbnail\":null,\"slug\":\"tips-kesehatan-keluarga-1\",\"updated_at\":\"2026-06-30T04:30:03.000000Z\"}','{\"content\":\"[{\\\"type\\\":\\\"paragraph\\\",\\\"co